#include <bits/stdc++.h>
using namespace std;
struct Node{
    int y,z;
    Node(int _y,int _z){y=_y,z=_z;};
};
int n,m,dist[5003];
vector<Node> g[5003];
bool b[5003];
int prim(){
    memset(dist,127,sizeof(dist));
    dist[1]=0;
    int ans=0,tot=0;
    for(;;){
    	int x=-1;
    	for(int i=1;i<=n;i++)
    		if(!b[i] && dist[i]<1<<30 && (x==-1 || dist[x]>dist[i]))x=i;
    	if(x==-1)break;
    	b[x]=true;
    	ans+=dist[x];
    	tot++;
    	for(int i=0;i<g[x].size();i++)
    		dist[g[x][i].y]=min(dist[g[x][i].y],g[x][i].z);
	}
	if(tot!=n)return -1;
	else return ans;
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=m;i++){
        int u,v,w;
        cin>>u>>v>>w;
        g[u].push_back(Node(v,w));
        g[v].push_back(Node(u,w));
    }
    int ans=prim();
    if(ans!=-1)cout<<ans;
    else cout<<"orz";
    return 0;
}
